import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import com.google.gson.Gson;
import java.lang.reflect.Field;

public class GsonTest {

  @Test
  public void testSerializeNullsDefaultFalse() throws Exception {
    // Create Gson instance with default constructor
    Gson gson = new Gson();

    // Access private field serializeNulls using reflection
    Field serializeNullsField = Gson.class.getDeclaredField("serializeNulls");
    serializeNullsField.setAccessible(true);

    // Set serializeNulls to false and test
    serializeNullsField.setBoolean(gson, false);
    assertFalse(gson.serializeNulls());

    // Set serializeNulls to true and test
    serializeNullsField.setBoolean(gson, true);
    assertTrue(gson.serializeNulls());
  }
}
